def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    arr = np.array(data, dtype=np.int32)
    arr.sort()
    return arr.tolist()

def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    return np.sort(np.fromiter(data, dtype=np.int32, count=len(data))).tolist()

def sort_list(data: list[int]) -> list[int]:
    import numpy as np
    arr = np.empty(len(data), dtype=np.int32)
    arr[:] = data
    arr.sort(kind='quicksort')
    return arr.tolist()
